import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"47. Annual Leave","description":"","frontmatter":{"title":"47. Annual Leave","eba":"Medical Specialists 2022-2026","topics":["leave","annual-leave","hours","rosters"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/47-annual-leave.md","filePath":"ebas/medical-specialists/leave/47-annual-leave.md"}'),r={name:"ebas/medical-specialists/leave/47-annual-leave.md"};function s(i,e,l,c,u,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_47-annual-leave" tabindex="-1">47. Annual Leave <a class="header-anchor" href="#_47-annual-leave" aria-label="Permalink to &quot;47. Annual Leave&quot;">​</a></h1><p><strong>47.1</strong> In accordance with the NES, a Doctor is entitled to four weeks’ annual leave and Shiftworkers are entitled to five weeks’ annual leave. The remainder of this clause contains additional provisions dealing with annual leave.</p><p><strong>47.2</strong> Doctors who are required by the Health Service to make themselves available to participate in the Health Service’s On-Call roster, and regularly accept calls from the Health Service, are entitled to five weeks’ annual leave (pro rata) each year.</p><p><strong>47.3</strong> A Shiftworker (as defined) is only entitled to a maximum of five weeks’ annual leave each year.</p><p><strong>47.4</strong> Taking paid annual leave</p><p>Paid annual leave may be taken for a period agreed between the Doctor and the Health Service.</p><p><strong>47.5</strong> Public holidays during annual leave</p><p>If a public holiday, as prescribed in this Agreement, falls within a period of annual leave, then extra time equivalent to the public holiday is added to the Doctor&#39;s annual leave.</p><p><strong>47.6</strong> Proportionate leave on termination</p><p>A Doctor whose employment is terminated will be paid in respect of all accrued and untaken paid annual leave entitlements.</p><p>Personal/carer&#39;s leave whilst on annual leave</p><p><strong>(a)</strong> Personal/carer&#39;s leave during a period of annual leave is dealt with in the NES.</p><p><strong>47.7</strong> Annual leave in advance</p><p><strong>(a)</strong> A Health Service and Doctor may agree in writing to the Doctor taking a period of paid annual leave before the employee has accrued an entitlement to the leave.</p><p><strong>(b)</strong> An agreement must state the amount of leave to be taken in advance and the date on which leave is to commence</p><p>NOTE: An example of the type of agreement required by subclause 47.7 is set out at <a href="/eba/ebas/medical-specialists/appendices/6-agreement-to-take-annual-leave-in-advance.html">Appendix 6</a> – Agreement to Take Annual Leave in Advance. There is no requirement to use the form of agreement set out at <a href="/eba/ebas/medical-specialists/appendices/6-agreement-to-take-annual-leave-in-advance.html">Appendix 6</a> – Agreement to Take Annual Leave in Advance.</p><p><strong>(c)</strong> The Health Service must keep a copy of any agreement under subclause</p><p><strong>47.7</strong> as a record.</p><p><strong>(d)</strong> If, on the termination of the Doctor’s employment, the Doctor has not accrued an entitlement to all of a period of paid annual leave already taken in accordance with an agreement under subclause 47.7, the Health Service may deduct from any money due to the Doctor on termination an amount equal to the amount that was paid to the Doctor in respect of any part of the period of annual leave taken in advance to which an entitlement has not been accrued.</p><p><strong>47.8</strong> Cashing out of annual leave</p><p><strong>(a)</strong> Paid annual leave must not be cashed out except in accordance with an agreement under subclause 47.8.</p><p><strong>(b)</strong> Each cashing out of a particular amount of paid annual leave must be the subject of a separate agreement under subclause 47.8.</p><p><strong>(c)</strong> A Health Service and a Doctor may agree in writing to the cashing out of a particular amount of accrued paid annual leave by the employee.</p><p><strong>(d)</strong> An agreement under subclause 47.8. must state:</p><p><strong>(i)</strong> the amount of leave to be cashed out and the payment to be made to the Doctor for it; and</p><p><strong>(ii)</strong> the date on which the payment is to be made.</p><p><strong>(e)</strong> An agreement under subclause 47.8 must be signed by the Health Service.</p><p><strong>(f)</strong> The payment must not be less than the amount that would have been payable had the Doctor taken the leave at the time the payment is made.</p><p><strong>(g)</strong> An agreement must not result in the Doctor’s remaining accrued entitlement to paid annual leave being less than 10 weeks.</p><p><strong>(h)</strong> The maximum amount of accrued paid annual leave that may be cashed out in any period of 12 months is 2 weeks.</p><p><strong>(i)</strong> The Health Service must keep a copy of any agreement under subclause</p><p><strong>47.8</strong> as an employee record.</p><p>NOTE 1: Under section 344 of the Act, an employer must not exert undue influence or undue pressure on an employee to make, or not make, an agreement under subclause 47.8.</p><p>NOTE 2: Under section 345(1) of the Act, a person must not knowingly or recklessly make a false or misleading representation about the workplace rights of another person under subclause 47.8.</p><p>NOTE 3: An example of the type of agreement required by subclause 47.8 is set out at form of agreement set out at <a href="/eba/ebas/medical-specialists/appendices/7-agreement-to-cash-out-annual-leave.html">Appendix 7</a>—Agreement to Cash Out Annual Leave.</p><p><strong>47.9</strong> Excessive annual leave accruals: general provision</p><p><strong>(a)</strong> A doctor has an excessive leave accrual if:</p><p><strong>(i)</strong> prior to 1 January 2023, the Doctor has accrued more than 15 weeks’ paid annual leave having regard to their current fraction; or</p><p><strong>(ii)</strong> on or after 1 January 2023, the Doctor has accrued more than 10 weeks’ paid annual leave having regard to their current fraction.</p><p><strong>(b)</strong> If a Doctor has an excessive leave accrual, the Health Service or the Doctor may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual.</p><p><strong>(c)</strong> Subclause 47.10 sets out how a Health Service may direct a Doctor who has an excessive annual leave accrual to take paid annual leave.</p><p><strong>(d)</strong> Subclause 47.11 sets out how a Doctor who has an excessive leave accrual may require a Health Service to grant paid annual leave requested by the Doctor.</p><p><strong>47.10</strong> Excessive annual leave accruals: Managing excess leave</p><p><strong>(a)</strong> If a Health Service has genuinely tried to reach agreement with a Doctor under subclause 47.9(b) but agreement is not reached (including because the Doctor refuses to confer), the Health Service may require the Doctor by a notice in writing to take one or more periods of paid annual leave. Any discussions should take into account the Doctor’s workload and the availability of suitable relief staff.</p><p><strong>(b)</strong> However, the requirement by the Health Service under subclause 47.10(a):</p><p><strong>(i)</strong> is of no effect if the doctor has made a request for leave in accordance with subclause 47.10 and such request has been declined in the previous 12 months; and</p><p><strong>(ii)</strong> is of no effect if it would result at any time in the Doctor’s remaining accrued entitlement to paid annual leave being less than 6 weeks when any other paid annual leave arrangements (whether made under subclauses 47.9, 47.10, or 47.11 or otherwise agreed by the Health Service and Doctor) are taken into account; and</p><p><strong>(iii)</strong> must not require the Doctor to take any period of paid annual leave of less than one week; and</p><p><strong>(iv)</strong> must not require the Doctor to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the direction is given; and</p><p><strong>(v)</strong> must not be inconsistent with any leave arrangement agreed by the Health Service and Doctor.</p><p><strong>(c)</strong> The Doctor must take paid annual leave in accordance with a notice under subclause 47.9(a) that is in effect.</p><p><strong>(d)</strong> A Doctor to whom a notice has been given under subclause 47.10(a) may request to take a period of paid annual leave as if the notice had not been given.</p><p>NOTE 1: Paid annual leave arising from a request mentioned in clause 47.10(d) may result in the direction ceasing to have effect. See subclause 47.11(b)(i).</p><p>NOTE 2: Under section 88(2) of the Act, the Health Service must not unreasonably refuse to agree to a request by the Doctor to take paid annual leave.</p><p><strong>47.11</strong> Excessive annual leave accruals: request by Doctor for leave</p><p><strong>(a)</strong> If a Doctor has genuinely tried to reach agreement with a Health Service under subclause 47.9(b) but agreement is not reached (including because the Health Service refuses to confer), the Doctor may give a written notice to the Health Service requesting to take one or more periods of paid annual leave.</p><p><strong>(b)</strong> However, a Doctor may only give a notice to the Health Service under subclause 47.11(a) if:</p><p><strong>(i)</strong> the Doctor has had an excessive leave accrual for more than 3 months at the time of giving the notice; and</p><p><strong>(ii)</strong> the Doctor has not been given a direction under subclause 47.10(a)that, when any other paid annual leave arrangements (whether made under subclause 47.9, 47.10, or 47.11 or otherwise agreed by the Health Service and Doctor) are taken into account, would eliminate the Doctor’s excessive leave accrual.</p><p><strong>(c)</strong> A notice given by a Doctor under subclause 47.10(a) must not:</p><p><strong>(i)</strong> if granted, result in the employee’s remaining accrued entitlement to paid annual leave being at any time less than 6 weeks when any other paid annual leave arrangements (whether made under subclause 47.9, 47.10, or 47.11 or otherwise agreed by the Health Service and Doctor) are taken into account; or</p><p><strong>(ii)</strong> provide for the Doctor to take any period of paid annual leave of less than one week; or</p><p><strong>(iii)</strong> provide for the Doctor to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the notice is given; or</p><p><strong>(iv)</strong> be inconsistent with any leave arrangement agreed by the Health Service and Doctor.</p><p><strong>(d)</strong> A Doctor is not entitled to request by a notice under subclause 47.11(a) more than 5 weeks’ paid annual leave in any period of 12 months.</p><p><strong>(e)</strong> The Health Service must grant paid annual leave requested by a notice under subclause 47.11(a).</p><p>Plain language terms: holidays, vacation.</p>',67)])])}const g=a(r,[["render",s]]);export{d as __pageData,g as default};
